export const adminDashboardDesign = {
  colors: {
    sidebar: "bg-gray-900 text-white",
    navbar: "bg-white shadow-md",
    accent: "text-indigo-600",
    hover: "hover:bg-gray-800",
  },

  layout: {
    wrapper: "flex min-h-screen",
    sidebar: "w-64 fixed left-0 top-0 h-full p-6 space-y-6",
    contentWrapper: "flex-1 flex flex-col ml-0 md:ml-64",
    navbar: "h-16 flex items-center justify-between px-6",
    content: "p-6",
    navItem: "px-3 py-2 rounded-lg transition cursor-pointer",
  },

  animation: {
    sidebar: {
      initial: { x: -200, opacity: 0 },
      animate: { x: 0, opacity: 1 },
      transition: { duration: 0.4 },
    },
    content: {
      initial: { opacity: 0 },
      animate: { opacity: 1 },
      transition: { duration: 0.5 },
    },
  },
};
